#!/usr/bin/env python3
import subprocess
import json
import sys
from pathlib import Path

def run_cmd(cmd):
    """Run a shell command safely and return stdout as text."""
    try:
        result = subprocess.run(
            cmd,
            capture_output=True,
            text=True,
            timeout=10,
            check=False,
        )
        if result.returncode != 0:
            sys.stderr.write(f"Command {' '.join(cmd)} failed: {result.stderr.strip()}\n")
            return None
        return result.stdout.strip()
    except subprocess.TimeoutExpired:
        sys.stderr.write(f"Command {' '.join(cmd)} timed out.\n")
        return None
    except Exception as e:
        sys.stderr.write(f"Error running {' '.join(cmd)}: {e}\n")
        return None

def get_cpu_info():
    out = run_cmd(['lscpu'])
    return out if out else "Unavailable"

def get_memory_info():
    out = run_cmd(['free', '-h'])
    return out if out else "Unavailable"

def get_disk_usage():
    out = run_cmd(['df', '-h', '--output=source,fstype,size,used,avail,pcent,target'])
    return out if out else "Unavailable"

def get_package_metadata():
    """
    Collect package metadata from the system's package manager.
    Supports dpkg (Debian/Ubuntu) and rpm (RHEL/Fedora).
    Returns a list of dicts with name, version, size, install_date.
    """
    packages = []

    # Debian based
    dpkg_path = Path('/usr/bin/dpkg')
    if dpkg_path.is_file():
        out = run_cmd(['dpkg-query', '-W', '-f=${Package}\t${Version}\t${Installed-Size}\t${Status}\n'])
        if out:
            for line in out.splitlines():
                try:
                    name, version, size_kb, status = line.split('\t')
                    if 'install ok installed' not in status:
                        continue
                    packages.append({
                        'name': name,
                        'version': version,
                        'size_kb': int(size_kb),
                        'install_date': None  # dpkg does not expose install date directly
                    })
                except ValueError:
                    continue

    # RPM based
    rpm_path = Path('/usr/bin/rpm')
    if rpm_path.is_file():
        out = run_cmd(['rpm', '-qa', '--queryformat', '%{NAME}\t%{VERSION}-%{RELEASE}\t%{SIZE}\t%{INSTALLTIME:date}\n'])
        if out:
            for line in out.splitlines():
                try:
                    name, version, size_bytes, install_date = line.split('\t')
                    packages.append({
                        'name': name,
                        'version': version,
                        'size_kb': int(int(size_bytes) / 1024),
                        'install_date': install_date
                    })
                except ValueError:
                    continue

    return packages

def summarize_packages(packages):
    total_pkgs = len(packages)
    total_size_kb = sum(p.get('size_kb', 0) for p in packages)
    avg_size_kb = total_size_kb / total_pkgs if total_pkgs else 0
    return {
        'total_packages': total_pkgs,
        'total_size_mb': round(total_size_kb / 1024, 2),
        'average_size_kb': round(avg_size_kb, 2)
    }

def main():
    print("=== System Benchmark from Package Metadata ===\n")

    print("CPU Information:")
    print(get_cpu_info() or "Unavailable")
    print("\nMemory Information:")
    print(get_memory_info() or "Unavailable")
    print("\nDisk Usage:")
    print(get_disk_usage() or "Unavailable")
    print("\nCollecting package metadata (this may take a few seconds)...")
    packages = get_package_metadata()
    if not packages:
        print("No package data collected.")
        return

    summary = summarize_packages(packages)
    print("\nPackage Summary:")
    print(json.dumps(summary, indent=2))

    # Show top 10 largest packages
    top_n = 10
    largest = sorted(packages, key=lambda p: p.get('size_kb', 0), reverse=True)[:top_n]
    print(f"\nTop {top_n} largest packages:")
    for pkg in largest:
        size_mb = round(pkg.get('size_kb', 0) / 1024, 2)
        date = pkg.get('install_date') or "N/A"
        print(f"{pkg['name']} {pkg['version']} - {size_mb} MB (installed: {date})")

if __name__ == "__main__":
    main()

